require_once __DIR__.'/functions.php';require_admin();$members=db()->query('SELECT id,email,display_name,email_verified_at,active,created_at FROM members ORDER BY created_at DESC')->fetchAll();render_header('Lectores',['robots'=>'noindex,nofollow']);?><section class="panel"><div class="moderation-title"><div><h1>Lectores</h1><p class="muted">Cuentas registradas y verificación.</p></div><span class="count-badge"><?=count($members)?></span></div><?php foreach($members as $m):?><article class="user-card"><div class="user-card-head"><div><strong><?=e($m['display_name'])?></strong><small><?=e($m['email'])?> · <?=e(format_date($m['created_at']))?></small></div><span class="status-badge <?=$m['active']?'approved':'pending'?>"><?=$m['active']?'Activo':'Suspendido'?></span></div><p class="muted"><?=$m['email_verified_at']?'Correo verificado':'Correo pendiente'?></p><form method="post" action="/member-action.php"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><input type="hidden" name="member_id" value="<?=(int)$m['id']?>"><button class="button <?=$m['active']?'danger-bg':''?>" name="action" value="<?=$m['active']?'suspend':'activate'?>"><?=$m['active']?'Suspender':'Activar'?></button></form></article><?php endforeach;?><?php if(!$members):?><p class="empty">Todavía no hay lectores.</p><?php endif;?></section><?php render_footer();
